\begin{tikzcd}
\tilde{\mathcal{M}}_{0,3} \arrow[r, hook] & \underset{\substack{\text{tous les autom.} \\ \text{à lacets de } \hat{\Pi}_{0,3}}}{\hat{\mathfrak{S}}_{0,3}} \arrow[r, "\text{action sur les}"] & \underset{\text{classes de lacets}}{\mathfrak{S}_3}
